"use client"

import { useState, useEffect } from "react";
import { encrypt } from "@/lib/crypto";

const page = () => {
    const [encrypted, setEncrypted] = useState<string | null>(null);

    const payload = {
        "amulet_reservation": {
            "prefix": "นาง",
            "first_name": "สมหญิง",
            "last_name": "ใจดี",
            "telephone_number": "0812345678",
            "address": "123 หมู่ 5"
        },
        "reservation_order_detail": [
            {
                "amulet_coin_id": "05ee9e3c-1f04-4a52-843a-4f37054e3e15",
                "total_quantity": 2
            },
            {
                "amulet_coin_id": "157c313f-3196-414c-b308-35bee2b315da",
                "total_quantity": 2
            },
            {
                "amulet_coin_id": "2e47009b-6afc-4824-96c8-2aef3653bbed",
                "total_quantity": 2
            }
        ],
        "reservation_order_image": {
            "image_base64": ""
        }
    };

    useEffect(() => {
        async function doEncrypt() {
            try {
                const plaintext = JSON.stringify(payload);
                const result = await encrypt(plaintext);
                setEncrypted(result);
                console.log("Encrypted:", result);
            } catch (err) {
                console.error("Encryption error:", err);
            }
        }
        doEncrypt();
    }, []); // eslint-disable-line react-hooks/exhaustive-deps

    return (
        <>
            <h1>ทดสอบ Encrypt</h1>

            {/* <h2>Payload (ข้อมูลจริง)</h2> */}
            {/* <pre>{JSON.stringify(payload, null, 2)}</pre> */}

            <h2>Encrypted (สิ่งที่เห็นใน Network Tab)</h2>
            {encrypted ? (
                <pre style={{ wordBreak: "break-all", whiteSpace: "pre-wrap" }}>
                    {JSON.stringify({ data: encrypted })}
                </pre>
            ) : (
                <p>กำลังเข้ารหัส...</p>
            )}
        </>
    );
}

export default page